    g.priority.player_with_priority = 0;
    for _ in 0..9 { let _ = g.process_suspend(); }
    drain_stack(&mut g);
    let k = g.battlefield_find(id).expect("Kraken on battlefield");
    assert_eq!((k.power(), k.toughness()), (6, 6));
