    g.step = TurnStep::PreCombatMain; // sorcery speed
    g.perform_action(GameAction::ActivateAbility {
        card_id: map, ability_index: 0, target: Some(Target::Permanent(bear)), x_value: None,
    }).expect("Map's sac-to-explore activates");
    drain_stack(&mut g);
