    g.plotted_this_turn.clear();
    let hand_before = g.players[0].hand.len();
    g.perform_action(GameAction::CastPlotted {
        card_id: id, target: None, additional_targets: vec![], mode: None, x_value: None,
    }).expect("cast plotted");
