// ── Cipher batch (CR 702.46) ──────────────────────────────────────────────────

fn precombat(g: &mut GameState) {
    g.step = TurnStep::PreCombatMain;
    g.active_player_idx = 0;
    g.priority.player_with_priority = 0;
}

#[test]
